function.body:
v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Record_ID VARCHAR2(32);
  v_Result NUMBER:=0;  --OBTG:NUMBER--
  v_AD_User_ID VARCHAR2(32);
  v_AD_Org_ID VARCHAR2(32);
  v_AD_Client_ID VARCHAR2(32);
  -- Parameter
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Consumption RECORD;
    Cur_Payment RECORD;
    Cur_Rel_Rev RECORD;
    Cur_Rel_Cost RECORD;

    -- Parameter Variables
    v_Total NUMBER; --OBTG:NUMBER--
   v_Line NUMBER:=0; --OBTG:NUMBER--
   v_CountConsumption NUMBER:=0; --OBTG:NUMBER--
   v_CountPayment NUMBER:=0; --OBTG:NUMBER--
   v_NoInserted NUMBER:=0; --OBTG:NUMBER--
   v_NoInserted2 NUMBER:=0; --OBTG:NUMBER--

   v_Docstatus	VARCHAR(60);
   v_IsLiquidated VARCHAR(1);
   v_TypeLiquidation VARCHAR(60);
   v_Docstatus2	VARCHAR(60);
   v_Posted	VARCHAR(1);
   v_Unprocessed VARCHAR(1);
   v_C_CosCenterID VARCHAR2(32);
 	v_count NUMBER;
	p_result VARCHAR(60);
	p_message VARCHAR(60);

  BEGIN
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
   BEGIN --BODY

    -- Get Parameters
    v_ResultStr:='ReadingParameters';
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        i.AD_USER_ID,
        i.AD_ORG_ID,
        i.AD_CLIENT_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
        ON i.AD_PInstance_ID=p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID=p_PInstance_ID
      ORDER BY p.SeqNo
      )
    LOOP
      v_Record_ID:=Cur_Parameter.Record_ID;
      v_AD_User_ID:=Cur_Parameter.AD_User_ID;
      v_AD_Org_ID:=Cur_Parameter.AD_Org_ID;
      v_AD_Client_ID:=Cur_Parameter.AD_Client_ID;
     END LOOP; -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_Record_ID) ;
    v_ResultStr:='CheckRestriction';

-- BEGIN Extension Point
    SELECT count(*) INTO v_count FROM DUAL
    WHERE EXISTS (SELECT 1 FROM ad_ep_procedures WHERE ad_extension_points_id = '557FA17D256E44AFA6750E99D61C5696');
    IF (v_count=1) THEN
      DECLARE
        v_ep_instance VARCHAR2(32);
        v_extension_point_id VARCHAR2(32) := '557FA17D256E44AFA6750E99D61C5696';
      BEGIN
        v_ep_instance := get_uuid();
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID', v_Record_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User', v_AD_User_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
        SELECT p_number INTO p_result
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Result';
        SELECT p_text INTO p_message
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Message';

        DELETE FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance;
      END;
    END IF;
    -- END Extension Point

    SELECT Docstatus, type_liquidation, posted,  Desprocessed, c_costcenter_id
    into v_Docstatus, v_TypeLiquidation , v_Posted, v_Unprocessed, v_C_CosCenterID
    FROM SSTPC_LIQUIDATION_PROJECTS 
    WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID;


    IF (v_Posted='N' and (v_Docstatus='CO' or  v_Docstatus='LQ') and v_Unprocessed='N') THEN 

		v_IsLiquidated:='N';

		IF (v_Docstatus='CO') THEN
			v_Docstatus2:= 'LQ';

		END IF;
		IF (v_Docstatus='LQ') THEN
			v_Docstatus2:= 'PL';

		END IF;



	    FOR Cur_Consumption IN(

		SELECT SCL.M_INOUTLINE_ID
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_CONSUMPTION_LINE SCL ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SCL.SSTPC_LIQUIDATION_PROJECTS_ID
		where SLP.SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID
	    )
	    LOOP
		UPDATE M_INOUTLINE SET EM_SSTPC_ISLIQUIDATED=v_IsLiquidated WHERE M_INOUTLINE_ID = Cur_Consumption.M_INOUTLINE_ID;
		v_NoInserted2:= v_NoInserted2 +1;


	   END LOOP;

	     FOR Cur_Payment IN(
		SELECT SP.FIN_PAYMENT_SCHEDULEDETAIL_ID
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_PAYMENT SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		where SLP.SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID
	    )
	    LOOP

		UPDATE FIN_PAYMENT_SCHEDULEDETAIL SET EM_SSTPC_ISLIQUIDATED=v_IsLiquidated WHERE FIN_PAYMENT_SCHEDULEDETAIL_ID = Cur_Payment.FIN_PAYMENT_SCHEDULEDETAIL_ID;

		v_NoInserted:= v_NoInserted +1;

	    END LOOP;  


	    --- Ingresos Relacionados

	    FOR Cur_Rel_Rev IN(

		SELECT SP.C_INVOICE_ID
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_RELATED_REVENUE SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		where SLP.SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID
	    )
	    LOOP

		UPDATE C_INVOICE SET EM_SSTPC_LIQUIDATE=v_IsLiquidated WHERE C_INVOICE_ID = Cur_Rel_Rev.C_INVOICE_ID;

		v_NoInserted:= v_NoInserted +1;

	    END LOOP;  

	    --- Fin Ingresos Relacionados


	    --- Costos Relacionados

	    FOR Cur_Rel_Cost IN(

		SELECT SP.C_INVOICELINE_ID
		FROM  SSTPC_LIQUIDATION_PROJECTS SLP
		JOIN SSTPC_RELATED_COSTS SP ON SLP.SSTPC_LIQUIDATION_PROJECTS_ID = SP.SSTPC_LIQUIDATION_PROJECTS_ID
		where SLP.SSTPC_LIQUIDATION_PROJECTS_ID =  v_Record_ID
	    )
	    LOOP

		UPDATE C_INVOICELINE SET EM_SSTPC_LIQUIDATE=v_IsLiquidated WHERE C_INVOICELINE_ID = Cur_Rel_Cost.C_INVOICELINE_ID;

		v_NoInserted:= v_NoInserted +1;

	    END LOOP;  

	    --- Fin Costos Relacionados



	    v_Message:= v_NoInserted2 || ' ' || '@RowsUpdated@' || '- Consumo' || '</br>' || v_NoInserted || ' ' || '@RowsUpdated@' || '- Pagos'; --'@Inserted@=' || v_NoInserted ;--|| ', @Updated@=' || v_NoUpdated;
	    --v_Result:=1; --    success

	IF (v_Docstatus2='LQ') THEN

	    UPDATE  SSTPC_LIQUIDATION_PROJECTS 
	    SET liquidate = 'N'
	    , docstatus = v_Docstatus2
	    , docstatuslist = 'DR'
	    , processed = 'N'
	    WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID;

	    UPDATE C_COSTCENTER 
	    SET EM_SSTPC_ISLIQUIDATED = 'N'
	    WHERE C_COSTCENTER_ID = v_C_CosCenterID;


	END IF;

	IF (v_Docstatus2='PL') THEN

	    UPDATE  SSTPC_LIQUIDATION_PROJECTS 
	    SET liquidate = 'N'
	    , docstatus = v_Docstatus2
	    , docstatuslist = 'DR'
	    ,desprocessed='Y'
	    WHERE SSTPC_LIQUIDATION_PROJECTS_ID = v_Record_ID;

	END IF;

    END IF ; 
	--Reactivar Centro de costos cuando la liquidacion sea Total.
    UPDATE C_Costcenter SET isactive='Y'
	WHERE C_Costcenter_id = (SELECT C_Costcenter_id FROM sstpc_liquidation_projects WHERE sstpc_liquidation_projects_id = v_Record_ID AND Type_Liquidation = 'TL' );
  	---
	 -- BEGIN Extension Point
    SELECT count(*) INTO v_count FROM DUAL
    WHERE EXISTS (SELECT 1 FROM ad_ep_procedures WHERE ad_extension_points_id = '6D2117F92889482FB3BFBE648DB4182B');
    IF (v_count=1) THEN
      DECLARE
        v_ep_instance VARCHAR2(32);
        v_extension_point_id VARCHAR2(32) := '6D2117F92889482FB3BFBE648DB4182B';
      BEGIN
        v_ep_instance := get_uuid();
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID', v_Record_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User', v_AD_User_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
        SELECT p_number INTO p_result
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Result';
        SELECT p_text INTO p_message
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Message';

        DELETE FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance;
      END;
    END IF;
    -- END Extension Point

-- BEGIN Extension Point
    SELECT count(*) INTO v_count FROM DUAL
    WHERE EXISTS (SELECT 1 FROM ad_ep_procedures WHERE ad_extension_points_id = '43028D8886714950B83DD6622A0EDD97');
    IF (v_count=1) THEN
      DECLARE
        v_ep_instance VARCHAR2(32);
        v_extension_point_id VARCHAR2(32) := '43028D8886714950B83DD6622A0EDD97';
      BEGIN
        v_ep_instance := get_uuid();
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID', v_Record_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User', v_AD_User_ID, NULL, NULL, NULL, NULL, NULL, NULL);
        AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
        SELECT p_number INTO p_result
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Result';
        SELECT p_text INTO p_message
        FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance
          AND parametername LIKE 'Message';

        DELETE FROM ad_ep_instance_para
        WHERE ad_ep_instance_id = v_ep_instance;
      END;
    END IF;
    -- END Extension Point

  	-------------------
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 1, v_Message) ;
    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
   ROLLBACK;
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  RETURN;
END SSTPC_UNPROCESS_LIQUIDATE
